module RefModule(
    input clk, 
    input reset, 
    output reg [5:0] lfsr);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset)
            lfsr <= 6'b000001;
        else
            lfsr <= {lfsr[4:0], lfsr[5] ^ lfsr[3]};
    end
endmodule
